                raise ValueError(f"Binary operator not allowed: {op_type.__name__}")
            return _BINARY_OPERATORS[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = self.visit(node.operand)
            op_type = type(node.op)
