class SafeEvaluator(ast.NodeVisitor):
    """
    A safe expression evaluator that only allows specific AST node types.
    Supports literals, arithmetic, comparisons, logical operations, and
    dictionary/list/tuple indexing with input_data.
    """

    def __init__(self, input_data: dict):
        self.input_data = input_data

    def visit(self, node):
        if isinstance(node, ast.Expression):
            return self.visit(node.body)
        elif isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
            return node.n
        elif isinstance(node, ast.Str):  # For Python < 3.8 compatibility
            return node.s
