            return [self.visit(elt) for elt in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(self.visit(elt) for elt in node.elts)
        elif isinstance(node, ast.Set):
            return {self.visit(elt) for elt in node.elts}
        elif isinstance(node, ast.Dict):
            keys = [self.visit(k) for k in node.keys]
            values = [self.visit(v) for v in node.values]
            return dict(zip(keys, values))
        elif isinstance(node, ast.Name):
            if node.id == 'input_data':
                return self.input_data
            raise NameError(f"Name '{node.id}' is not allowed. Only 'input_data' is permitted.")
        elif isinstance(node, ast.Subscript):
            value = self.visit(node.value)
            if isinstance(node.slice, ast.Index):  # For Python < 3.9 compatibility
                slice_val = self.visit(node.slice.value)
            else:
                slice_val = self.visit(node.slice)
            return value[slice_val]
        elif isinstance(node, ast.Attribute):
            obj = self.visit(node.value)
            # Allow accessing attributes like .get(), .keys(), etc. on dicts
            attr_name = node.attr
            if isinstance(obj, dict) and attr_name in ('get', 'keys', 'values', 'items'):
                return getattr(obj, attr_name)
            raise AttributeError(f"Attribute access '{attr_name}' is not allowed.")
