            func = self.visit(node.func)
            args = [self.visit(arg) for arg in node.args]
            kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}
            # Only allow calling methods retrieved from allowed objects (like dict.get)
            return func(*args, **kwargs)
        elif isinstance(node, ast.BinOp):
            left = self.visit(node.left)
            right = self.visit(node.right)
            op_type = type(node.op)
            if op_type not in _BIN_OPS:
                raise TypeError(f"Binary operator {op_type.__name__} is not allowed.")
            return _BIN_OPS[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = self.visit(node.operand)
            op_type = type(node.op)
            if op_type not in _UNARY_OPS:
                raise TypeError(f"Unary operator {op_type.__name__} is not allowed.")
            return _UNARY_OPS[op_type](operand)
        elif isinstance(node, ast.BoolOp):
            values = [self.visit(v) for v in node.values]
            if isinstance(node.op, ast.And):
                result = True
                for v in values:
                    result = result and v
                    if not result:
                        break
                return result
            elif isinstance(node.op, ast.Or):
                result = False
                for v in values:
                    result = result or v
                    if result:
                        break
                return result
            else:
                raise TypeError(f"Boolean operator {type(node.op).__name__} is not allowed.")
        elif isinstance(node, ast.Compare):
            left = self.visit(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                right = self.visit(comparator)
                op_type = type(op)
                if op_type not in _CMP_OPS:
                    raise TypeError(f"Comparison operator {op_type.__name__} is not allowed.")
                if not _CMP_OPS[op_type](left, right):
                    return False
                left = right
            return True
        elif isinstance(node, ast.IfExp):
            test = self.visit(node.test)
            if test:
                return self.visit(node.body)
            else:
                return self.visit(node.orelse)
        elif isinstance(node, ast.Expr):
            return self.visit(node.value)
        else:
            raise TypeError(f"Expression contains disallowed syntax: {type(node).__name__}")


